import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
};

function generateOTP(): string {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

function normalizePhone(phone: string): string {
  let cleaned = phone.replace(/[^\d+]/g, "");
  if (cleaned.startsWith("07")) {
    cleaned = "+263" + cleaned.slice(1);
  } else if (cleaned.startsWith("263") && !cleaned.startsWith("+")) {
    cleaned = "+" + cleaned;
  }
  return cleaned;
}

function isValidZimbabwePhone(phone: string): boolean {
  const normalized = normalizePhone(phone);
  return /^\+263(71|73|77|78)\d{7}$/.test(normalized);
}

async function sendSMS(
  supabase: ReturnType<typeof createClient>,
  phoneNumber: string,
  message: string
): Promise<{ success: boolean; status: string; error?: string }> {
  const { data: config, error: configError } = await supabase
    .from("sms_config")
    .select("*")
    .eq("id", "sms_config_singleton")
    .single();

  if (configError || !config) {
    console.error("[SMS] Failed to load SMS config:", configError);
    return { success: false, status: "config_error", error: "SMS configuration not found" };
  }

  if (!config.enabled) {
    console.log("[SMS] SMS service is disabled, OTP logged:", message);
    return { success: true, status: "disabled" };
  }

  if (config.test_mode) {
    console.log("[SMS] TEST MODE - OTP for", phoneNumber, ":", message);
    return { success: true, status: "test_mode" };
  }

  const apiUrl: string = config.api_url;
  const apiKey: string = config.api_key;
  const senderId: string = config.sender_id || "ZimCommute";

  // locahost.co.zw API requires: apiKey, senderId, recipient, message
  const payload = {
    apiKey,
    senderId,
    recipient: phoneNumber,
    message,
  };

  console.log("[SMS] Sending to", phoneNumber, "via", apiUrl, "senderId:", senderId);

  try {
    const response = await fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    const responseText = await response.text();
    console.log("[SMS] Provider response status:", response.status);
    console.log("[SMS] Provider response body:", responseText);

    let responseData: Record<string, unknown> = {};
    try {
      responseData = JSON.parse(responseText);
    } catch {
      responseData = { raw: responseText };
    }

    if (!response.ok) {
      const errMsg = (responseData.message as string) || (responseData.error as string) || responseText;
      console.error("[SMS] Provider error HTTP", response.status, ":", errMsg);
      return { success: false, status: "provider_error", error: errMsg };
    }

    // Some providers return 200 but with a failure status in the body
    if (responseData.status && responseData.status !== "success" && responseData.status !== "200") {
      const errMsg = (responseData.message as string) || (responseData.description as string) || responseText;
      console.error("[SMS] Provider returned failure in body:", errMsg);
      return { success: false, status: "provider_error", error: errMsg };
    }

    console.log("[SMS] Sent successfully to", phoneNumber);
    return { success: true, status: "sent" };
  } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error("[SMS] Connection error:", errMsg);
    return { success: false, status: "connection_error", error: errMsg };
  }
}

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  const url = new URL(req.url);
  const path = url.pathname.replace(/^\/otp/, "");

  const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

  try {
    const body = await req.json();

    // POST /otp/send or /otp/resend
    if ((path === "/send" || path === "/resend") && req.method === "POST") {
      const { phoneNumber } = body;

      if (!phoneNumber) {
        return new Response(
          JSON.stringify({ success: false, message: "Phone number is required" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const normalizedPhone = normalizePhone(phoneNumber);

      if (!isValidZimbabwePhone(normalizedPhone)) {
        return new Response(
          JSON.stringify({ success: false, message: "Please enter a valid Zimbabwe phone number" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      // Rate limiting: max 3 OTPs per hour per phone
      const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
      const { count } = await supabase
        .from("otp_verifications")
        .select("*", { count: "exact", head: true })
        .eq("phone_number", normalizedPhone)
        .gte("created_at", oneHourAgo);

      if ((count ?? 0) >= 3) {
        return new Response(
          JSON.stringify({ success: false, message: "Too many OTP requests. Please wait 1 hour before trying again." }),
          { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      // Generate OTP
      const otp = generateOTP();
      const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();

      // Delete any existing unverified OTPs for this phone
      await supabase
        .from("otp_verifications")
        .delete()
        .eq("phone_number", normalizedPhone)
        .eq("verified", false);

      // Store new OTP
      const { error: insertError } = await supabase
        .from("otp_verifications")
        .insert({
          phone_number: normalizedPhone,
          otp,
          expires_at: expiresAt,
          verified: false,
          attempts: 0,
        });

      if (insertError) {
        console.error("[OTP] Failed to store OTP:", insertError);
        return new Response(
          JSON.stringify({ success: false, message: "Failed to generate OTP. Please try again." }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      console.log("[OTP] Generated for", normalizedPhone, "- OTP:", otp);

      // Send SMS
      const smsMessage = `Your ZimCommute verification code is: ${otp}. Valid for 5 minutes. Do not share this code.`;
      const smsResult = await sendSMS(supabase, normalizedPhone, smsMessage);

      if (!smsResult.success) {
        console.error("[OTP] SMS delivery failed:", smsResult.error, "| OTP for manual lookup:", otp);
        // Return 200 so the app can still proceed to the OTP entry screen,
        // but surface the real provider error message to help diagnose
        return new Response(
          JSON.stringify({
            success: false,
            message: `SMS delivery failed: ${smsResult.error || smsResult.status}`,
            smsStatus: smsResult.status,
            smsError: smsResult.error,
          }),
          { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      return new Response(
        JSON.stringify({
          success: true,
          message: "OTP sent successfully via SMS",
          expiresIn: 300,
          smsStatus: smsResult.status,
        }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // POST /otp/verify
    if (path === "/verify" && req.method === "POST") {
      const { phoneNumber, otp } = body;

      if (!phoneNumber || !otp) {
        return new Response(
          JSON.stringify({ success: false, message: "Phone number and OTP are required" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const normalizedPhone = normalizePhone(phoneNumber);

      const { data: otpRecord, error: otpError } = await supabase
        .from("otp_verifications")
        .select("*")
        .eq("phone_number", normalizedPhone)
        .eq("verified", false)
        .order("created_at", { ascending: false })
        .limit(1)
        .single();

      if (otpError || !otpRecord) {
        return new Response(
          JSON.stringify({ success: false, message: "No pending OTP found. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      if (new Date(otpRecord.expires_at) < new Date()) {
        return new Response(
          JSON.stringify({ success: false, message: "OTP has expired. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      if (otpRecord.attempts >= 5) {
        return new Response(
          JSON.stringify({ success: false, message: "Too many failed attempts. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      await supabase
        .from("otp_verifications")
        .update({ attempts: otpRecord.attempts + 1 })
        .eq("id", otpRecord.id);

      if (otpRecord.otp !== otp.toString()) {
        const remaining = 5 - (otpRecord.attempts + 1);
        return new Response(
          JSON.stringify({
            success: false,
            message: `Invalid code. ${remaining > 0 ? `${remaining} attempts remaining.` : "Please request a new code."}`,
          }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      await supabase
        .from("otp_verifications")
        .update({ verified: true })
        .eq("id", otpRecord.id);

      const { data: user, error: userError } = await supabase
        .from("users")
        .upsert(
          { phone_number: normalizedPhone, updated_at: new Date().toISOString() },
          { onConflict: "phone_number", ignoreDuplicates: false }
        )
        .select()
        .single();

      if (userError || !user) {
        console.error("[OTP] Failed to upsert user:", userError);
        return new Response(
          JSON.stringify({ success: false, message: "Failed to create user account. Please try again." }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const token = `user_${user.id}`;
      console.log("[OTP] Verified for", normalizedPhone, "user:", user.id);

      return new Response(
        JSON.stringify({
          success: true,
          token,
          user: {
            id: user.id,
            phoneNumber: user.phone_number,
            fullName: user.full_name,
            email: user.email,
            profilePhotoUrl: user.profile_photo_url,
            userType: user.user_type,
            homeCity: user.home_city,
            verificationLevel: user.verification_level,
            role: user.role,
            walletBalance: user.wallet_balance,
            isBanned: user.is_banned,
            banReason: user.ban_reason,
            createdAt: user.created_at,
            updatedAt: user.updated_at,
          },
        }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    return new Response(
      JSON.stringify({ success: false, message: "Not found" }),
      { status: 404, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error("[OTP] Unhandled error:", errMsg);
    return new Response(
      JSON.stringify({ success: false, message: "Internal server error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

